--
-- Structure de la table `commandes_sa`
--

DROP TABLE IF EXISTS `commandes_sa`;
CREATE TABLE IF NOT EXISTS `commandes_sa` (
  `Numero_de_commande` int DEFAULT NULL,
  `Etat_de_la_commande` varchar(255) DEFAULT NULL,
  `Date_de_commande` varchar(255) DEFAULT NULL,
  `Note_du_client` varchar(255) DEFAULT NULL,
  `Prenom__Facturation` varchar(255) DEFAULT NULL,
  `NOM_DE_FAMILLE__FACTURATION` varchar(255) DEFAULT NULL,
  `Societe__Facturation` varchar(255) DEFAULT NULL,
  `Adresse_1___2__Facturation` varchar(255) DEFAULT NULL,
  `Ville__Facturation` varchar(255) DEFAULT NULL,
  `Code_de_l_etat__Facturation` varchar(255) DEFAULT NULL,
  `Code_postal__Facturation` varchar(255) DEFAULT NULL,
  `Code_du_pays__Facturation` varchar(255) DEFAULT NULL,
  `Prenom__Livraison` varchar(255) DEFAULT NULL,
  `NOM_DE_FAMILLE__LIVRAISON` varchar(255) DEFAULT NULL,
  `Adresse_1___2__Livraison` varchar(255) DEFAULT NULL,
  `Ville__Livraison` varchar(255) DEFAULT NULL,
  `Code_de_l_etat__Livraison` varchar(255) DEFAULT NULL,
  `Code_postal__Livraison` varchar(255) DEFAULT NULL,
  `Code_du_pays__Livraison` varchar(255) DEFAULT NULL,
  `Titre_de_la_methode_de_paiement` varchar(255) DEFAULT NULL,
  `Montant_de_la_remise_panier` varchar(255) DEFAULT NULL,
  `Cart_Discount_Amount_inc__tax` varchar(255) DEFAULT NULL,
  `Sous_total_de_la_commande` varchar(255) DEFAULT NULL,
  `Titre_de_la_methode_de_livraison` varchar(255) DEFAULT NULL,
  `Montant_de_la_livraison` varchar(255) DEFAULT NULL,
  `Montant_du_remboursement_de_la_commande` varchar(255) DEFAULT NULL,
  `Montant_total_de_la_commande` varchar(255) DEFAULT NULL,
  `Montant_total_de_la_taxe` varchar(255) DEFAULT NULL,
  `UGS` varchar(255) DEFAULT NULL,
  `Article` varchar(255) DEFAULT NULL,
  `Nom_de_l_element` varchar(500) DEFAULT NULL,
  `Quantite____Remboursement` varchar(255) DEFAULT NULL,
  `Prix_du_produit` varchar(255) DEFAULT NULL,
  `Code_promo` varchar(255) DEFAULT NULL,
  `Reduction` varchar(255) DEFAULT NULL,
  `Taxe_de_la_reduction` varchar(255) DEFAULT NULL
) ENGINE=MyISAM DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

