(14023, 'simple', 'TAB-AC-ZA', 'Lâarbre du crÃĐpuscule', 'Shop, Tableaux dâart', '1', 'visible', '0', '150', '120', '1', '1', '<h3 data-start=\"268\" data-end=\"287\"><strong data-start=\"272\" data-end=\"285\">Artiste :</strong></h3><h3 data-start=\"268\" data-end=\"287\"><strong data-start=\"288\" data-end=\"304\">Zayneb Abidi</strong><br data-start=\"304\" data-end=\"307\"><br>Doctorante en Architecture â rÃĐsidente en France</h3><h3 data-start=\"359\" data-end=\"380\"><strong data-start=\"363\" data-end=\"378\">Technique :</strong></h3><p data-start=\"381\" data-end=\"427\">Peinture acrylique sur toile canvas de coton</p><h3 data-start=\"429\" data-end=\"451\"><strong data-start=\"433\" data-end=\"449\">Dimensions :</strong></h3><p data-start=\"452\" data-end=\"487\">30*25Â </p><h3 data-start=\"489\" data-end=\"518\"><strong data-start=\"493\" data-end=\"516\">AnnÃĐe de crÃĐation :</strong></h3><p data-start=\"519\" data-end=\"525\">2025</p><p><em data-start=\"562\" data-end=\"585\">LâArbre du CrÃĐpuscule</em> capture un moment suspendu entre le jour et la nuit, oÃđ le ciel se teinte de bleu profond et les ÃĐtoiles commencent Ã  naÃŪtre.<br data-start=\"711\" data-end=\"714\"><br>Lâarbre, solitaire mais apaisÃĐ, se dresse comme un symbole de <strong data-start=\"776\" data-end=\"805\">rÃĐsilience et dâÃĐquilibre</strong>, reliant la terre Ã  lâimmensitÃĐ cÃĐleste.<br data-start=\"846\" data-end=\"849\"><br>La douceur du dÃĐgradÃĐ bleu et le contraste du noir ÃĐvoquent Ã  la fois la <strong data-start=\"922\" data-end=\"954\">quiÃĐtude du silence nocturne</strong> et la <strong data-start=\"961\" data-end=\"994\">force tranquille de la nature</strong>.</p>', 'taxable', '120'),
(14031, 'simple', 'TAB-CM-ZA', 'Couleurs de la MÃĐdina', 'Shop, Tableaux dâart', '1', 'visible', '0', '150', '120', '1', '1', '<h3 data-start=\"202\" data-end=\"221\"><strong data-start=\"206\" data-end=\"219\">Artiste :</strong></h3><p data-start=\"222\" data-end=\"291\"><strong data-start=\"222\" data-end=\"238\">Zayneb Abidi</strong><br data-start=\"238\" data-end=\"241\"><br>Doctorante en Architecture â rÃĐsidente en France</p><h3 data-start=\"293\" data-end=\"314\"><strong data-start=\"297\" data-end=\"312\">Technique :</strong></h3><p data-start=\"315\" data-end=\"352\">Peinture acrylique sur toile canvas</p><h3 data-start=\"354\" data-end=\"376\"><strong data-start=\"358\" data-end=\"374\">Dimensions :</strong></h3><p data-start=\"377\" data-end=\"389\">30 Ã 25 cm</p><h3 data-start=\"391\" data-end=\"414\"><strong data-start=\"395\" data-end=\"412\">Description :</strong></h3><p data-start=\"415\" data-end=\"876\">Cette Åuvre intitulÃĐe <em data-start=\"437\" data-end=\"462\">âCouleurs de la MÃĐdinaâ</em> rend hommage Ã  lâarchitecture tunisienne traditionnelle Ã  travers une composition gÃĐomÃĐtrique et harmonieuse.<br data-start=\"572\" data-end=\"575\"><br>Les dÃĐgradÃĐs de <strong data-start=\"591\" data-end=\"629\">rouge, orange, jaune, vert et bleu</strong> sâempilent tel un paysage urbain stylisÃĐ, rappelant les ruelles, les dÃīmes et les toits des anciennes mÃĐdinas.<br data-start=\"740\" data-end=\"743\"><br>Chaque couleur symbolise une ambiance : la chaleur du sud, la lumiÃĻre du littoral, la sÃĐrÃĐnitÃĐ du ciel et la profondeur de la nuit.</p>', 'taxable', '120'),
(14037, 'simple', 'TAB-DJ-ZA', 'Douceur de Djerba', 'Shop, Tableaux dâart', '1', 'visible', '0', '150', '120', '1', '1', '<h3 data-start=\"202\" data-end=\"221\"><strong data-start=\"206\" data-end=\"219\">Artiste :</strong></h3><p data-start=\"222\" data-end=\"291\"><strong data-start=\"222\" data-end=\"238\">Zayneb Abidi</strong><br data-start=\"238\" data-end=\"241\">\\nDoctorante en Architecture â rÃĐsidente en France</p><h3 data-start=\"293\" data-end=\"314\"><strong data-start=\"297\" data-end=\"312\">Technique :</strong></h3><p data-start=\"315\" data-end=\"352\">Peinture acrylique sur toile canvas</p><h3 data-start=\"354\" data-end=\"376\"><strong data-start=\"358\" data-end=\"374\">Dimensions :</strong></h3><p data-start=\"377\" data-end=\"389\">30 Ã 25 cm</p><h3 data-start=\"391\" data-end=\"425\"><strong data-start=\"395\" data-end=\"423\">Description de lâÅuvre :</strong></h3><p>\\n\\n\\n\\n\\n\\n\\n</p><p data-start=\"426\" data-end=\"853\"><em data-start=\"426\" data-end=\"445\">Douceur de Djerba</em> capture un instant paisible de la vie insulaire tunisienne : une femme assise, profitant de lâombre dâun jardin fleuri face Ã  une faÃ§ade typique aux volets bleus.<br data-start=\"608\" data-end=\"611\">\\nLes couleurs douces â vert olive, bleu azur et rose poudrÃĐ â traduisent la <strong data-start=\"686\" data-end=\"722\">sÃĐrÃĐnitÃĐ et la lumiÃĻre apaisante</strong> de lâÃŪle de Djerba.<br data-start=\"742\" data-end=\"745\">\\nLâÅuvre reflÃĻte la <strong data-start=\"764\" data-end=\"789\">grÃĒce mÃĐditerranÃĐenne</strong>, entre architecture traditionnelle et atmosphÃĻre de quiÃĐtude.</p>', 'taxable', '120');
